$(document).ready(function(){$(".action-slider").click(function(){$("#actions-box-slider").slideToggle("fast");$(this).toggleClass("activated");return false})});$(document).ready(function(){$(".forgot-pwd").click(function(){$("#loginbox").hide();$("#forgotbox").show();return false})});$(document).ready(function(){$(".back-login").click(function(){$("#loginbox").show();$("#forgotbox").hide();return false})});$(document).bind("click",function(a){a.target.id!=$(".action-slider").attr("class")&&$("#actions-box-slider").slideUp()});